// Generated by Claude Opus 4.6

import { BackupInfo, BackupStatus } from '@eclipse-che/common';
import {
  Alert,
  AlertVariant,
  ClipboardCopy,
  ClipboardCopyVariant,
  DescriptionList,
  DescriptionListDescription,
  DescriptionListGroup,
  DescriptionListTerm,
  HelperText,
  HelperTextItem,
} from '@patternfly/react-core';
import cron from 'cron-parser';
import cronstrue from 'cronstrue';
import React from 'react';

import { BackupStatusBadge } from '@/components/BackupStatusBadge';
import { formatDate, formatRelativeDate } from '@/services/helpers/dates';

type Props = {
  backupInfo: BackupInfo;
  isWorkspaceStopped: boolean;
};

export class BackupTabInfo extends React.PureComponent<Props> {
  private getScheduleHelperText(): string {
    const { status } = this.props.backupInfo;
    const { isWorkspaceStopped } = this.props;

    switch (status) {
      case BackupStatus.NEVER:
        return 'Backups run only when the workspace is stopped.';
      case BackupStatus.IN_PROGRESS:
        return 'Backup is in progress.';
      case BackupStatus.UNAVAILABLE:
        return 'Backup image was not found in the registry.';
      case BackupStatus.FAILED:
        return isWorkspaceStopped
          ? 'Will retry on next scheduled run.'
          : 'Will retry when the workspace stops.';
      default:
        return isWorkspaceStopped
          ? 'Backup is current.'
          : 'Backup will run when the workspace stops.';
    }
  }

  private formatSchedule(schedule?: string): string {
    if (!schedule) {
      return 'Not configured';
    }
    try {
      return cronstrue.toString(schedule);
    } catch {
      return schedule;
    }
  }

  private formatNextRun(schedule?: string): string | undefined {
    if (!schedule) {
      return undefined;
    }
    try {
      const nextDate = cron.parse(schedule).next().toDate();
      return `Next run: ${formatRelativeDate(nextDate)} (${formatDate(nextDate)})`;
    } catch {
      return undefined;
    }
  }

  private formatLastBackupTime(lastBackupTime?: string): string {
    if (!lastBackupTime) {
      return 'Never';
    }
    const date = new Date(lastBackupTime);
    return `${formatRelativeDate(date)} (${formatDate(date)})`;
  }

  public render(): React.ReactElement {
    const {
      status,
      lastBackupTime,
      backupImageUrl,
      backupSchedule,
      error: backupError,
    } = this.props.backupInfo;

    return (
      <DescriptionList isHorizontal>
        <DescriptionListGroup>
          <DescriptionListTerm>Status</DescriptionListTerm>
          <DescriptionListDescription>
            <BackupStatusBadge
              status={status}
              lastBackupTime={lastBackupTime}
              backupImageUrl={backupImageUrl}
            />
          </DescriptionListDescription>
        </DescriptionListGroup>

        {status === BackupStatus.FAILED && backupError && (
          <DescriptionListGroup>
            <DescriptionListTerm>Error</DescriptionListTerm>
            <DescriptionListDescription>
              <Alert
                variant={AlertVariant.danger}
                title="Backup failed"
                isInline
                isPlain
                data-testid="backup-error-message"
              >
                {backupError}
              </Alert>
            </DescriptionListDescription>
          </DescriptionListGroup>
        )}

        {backupSchedule && (
          <DescriptionListGroup>
            <DescriptionListTerm>Backup Schedule</DescriptionListTerm>
            <DescriptionListDescription>
              {this.formatSchedule(backupSchedule)}
              {this.formatNextRun(backupSchedule) && (
                <HelperText>
                  <HelperTextItem variant="indeterminate">
                    {this.formatNextRun(backupSchedule)}
                  </HelperTextItem>
                </HelperText>
              )}
              <HelperText>
                <HelperTextItem variant="indeterminate">
                  {this.getScheduleHelperText()}
                </HelperTextItem>
              </HelperText>
            </DescriptionListDescription>
          </DescriptionListGroup>
        )}

        {status !== BackupStatus.NEVER && status !== BackupStatus.UNAVAILABLE && (
          <>
            <DescriptionListGroup>
              <DescriptionListTerm>Last Backup</DescriptionListTerm>
              <DescriptionListDescription>
                {this.formatLastBackupTime(lastBackupTime)}
              </DescriptionListDescription>
            </DescriptionListGroup>

            {backupImageUrl && (
              <DescriptionListGroup>
                <DescriptionListTerm>Backup Image</DescriptionListTerm>
                <DescriptionListDescription>
                  <ClipboardCopy
                    isReadOnly
                    variant={ClipboardCopyVariant.inline}
                    hoverTip="Copy"
                    clickTip="Copied"
                  >
                    {backupImageUrl}
                  </ClipboardCopy>
                </DescriptionListDescription>
              </DescriptionListGroup>
            )}
          </>
        )}
      </DescriptionList>
    );
  }
}
